import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Container, Row, Col, Card, Form, Button, Alert } from 'react-bootstrap';

const DebugLogin = () => {
  const { authFetch } = useAuth();
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const res = await authFetch('/api/debug/data', {
        headers: {
          'Authorization': `Bearer ${password}`
        }
      });

      if (res.ok) {
        const data = await res.json();
        // Store debug token in sessionStorage for debug dashboard
        sessionStorage.setItem('debugToken', password);
        navigate('/debug');
      } else {
        setError('Invalid debug password');
      }
    } catch (err) {
      setError('Debug access failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container className="mt-4">
      <Row className="justify-content-center">
        <Col md={6}>
          <Card>
            <Card.Header>
              <h4 className="text-center">🔍 Debug Access</h4>
            </Card.Header>
            <Card.Body>
              <Alert variant="info" className="mb-3">
                <strong>Debug Dashboard Access</strong><br/>
                Enter debug password to access system data and user information.
              </Alert>

              <Form onSubmit={handleSubmit}>
                <Form.Group className="mb-3">
                  <Form.Label>Debug Password</Form.Label>
                  <Form.Control
                    type="password"
                    placeholder="Enter debug password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                </Form.Group>

                {error && <Alert variant="danger">{error}</Alert>}

                <Button variant="primary" type="submit" disabled={loading}>
                  {loading ? 'Accessing...' : 'Access Debug Dashboard'}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
};

export default DebugLogin;
